@startuml
package "com" {
    package "iluwatar" {
        package "multiton" {
            class App {
                - LOGGER : Logger
                + App()
                + main(args : String[])
            }

            enum NazgulName <<enumeration>> {
                ADUNAPHEL
                AKHORAHIL
                DWAR
                HOARMURATH
                JI_INDUR
                KHAMUL
                MURAZOR
                REN
                UVATHA

                valueOf(name : String) : NazgulName
                values() : NazgulName[]
            }

            class Nazgul {
                name : NazgulName
                nazguls : Map<NazgulName, Nazgul>

                Nazgul(name : NazgulName)
                getInstance(name : NazgulName) : Nazgul
                getName() : NazgulName
            }

            ' Relationships based on visual cues in original image
            Nazgul --> NazgulName : "-name>" 
        }
    }
}
@enduml
